                other_details.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                other_details.append(f"has a runway surface made of {obj}")
            elif predicate == "division":
                other_details.append(f"belongs to the division of {obj}")
            elif predicate == "class":
                other_details.append(f"belongs to the class of {obj}")
            else:
                if predicate.endswith("Length") or predicate.endswith("LengthFeet") or predicate.endswith("LengthMetre"):
                    other_details.append(f"has a {predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', '').replace('Feet', '').replace('Metre', '')} of {obj}")
                elif predicate == "country":
                    location_details.append(f"is located in {obj}")
                elif predicate == "location":
                    location_details.append(f"is located in {obj}")
                else:
                    if predicate in ["officialLanguage", "language", "capital"]:
                        location_details.append(f"is {obj}")
                    else:
                        other_details.append(f"has a {predicate} of {obj}")
        if location_details or other_details:
            if location_details and other_details:
                base += " " + ", ".join(location_details) + " and " + ", ".join(other_details)
            elif location_details:
                base += " " + ", ".join(location_details)
            else:
                base += " " + ", ".join(other_details)
            sentences.append(base + ".")

    # Join sentences with appropriate connectors
    if len(sentences) == 1:
        return sentences[0]
    else:
        return " ".join(sentences)

